import numpy as np

class KMeansLite:
    def __init__(self, k: int = 4):
        self.k = k
        self._centroids = None

    def _init_centroids(self, X):
        # BUG: taking mean over axis=1 collapses to (K,) instead of (K, D)
        init = X[:self.k]
        self._centroids = init.mean(axis=1)  # shape (K,) — WRONG

    def compute_features(self, points, centroids):
        try:
            diffs = points - centroids  # (N, 3) - (K,) -> cannot broadcast
            return np.linalg.norm(diffs, axis=-1)
        except ValueError as e:
            raise ValueError(
                f"shape mismatch: points={points.shape} centroids={centroids.shape}; "
                f"expected centroids (K,3)"
            ) from e

    def _compute_all(self):
        feats = []
        for batch in self._batches:
            feats.append(self.compute_features(batch, self._centroids))
        return feats

    def fit(self, X, batches):
        self._init_centroids(X)
        self._batches = batches
        return self._compute_all()

if __name__ == '__main__':
    X = np.random.rand(1000, 3)
    km = KMeansLite(4)
    km.fit(X, [np.random.rand(512, 3) for _ in range(8)])
